class Solution {
    public List<List<String>> findDuplicate(String[] paths) {
        Map<String, List<String>> contentMap = new HashMap<>();
        for (String path : paths) {
            String[] dirFiles = path.split(" ");
            String dir = dirFiles[0];
            for (int i = 1; i < dirFiles.length; i++) {
                int idx = dirFiles[i].indexOf('(');
                String file = dir + "/" + dirFiles[i].substring(0, idx);
                String content = dirFiles[i].substring(idx + 1, dirFiles[i].length() - 1);
                contentMap.computeIfAbsent(content, k -> new ArrayList<>()).add(file);
            }
        }
        List<List<String>> res = new ArrayList<>();
        for (List<String> files : contentMap.values()) {
            if (files.size() > 1) {
                res.add(files);
            }
        }
        return res;
    }
}
